DROP TABLE IF EXISTS jobs;
CREATE TABLE jobs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  kjno TEXT UNIQUE,
  employer TEXT NOT NULL,
  title TEXT,
  rank TEXT,
  score INTEGER,
  area TEXT,
  prefecture TEXT,
  work_location TEXT,
  salary_form TEXT,
  salary_min INTEGER,
  salary_max INTEGER,
  salary_display TEXT,
  bonus_text TEXT,
  holidays INTEGER,
  emp_type TEXT,
  station_text TEXT,
  shift1 TEXT,
  shift2 TEXT,
  description TEXT,
  welfare TEXT,
  score_sal INTEGER,
  score_hol INTEGER,
  score_bon INTEGER,
  score_emp INTEGER,
  score_wel INTEGER,
  score_loc INTEGER,
  contract_period TEXT,
  insurance TEXT,
  synced_at TEXT,
  first_seen_at TEXT
);
CREATE INDEX IF NOT EXISTS idx_jobs_area ON jobs(area);
CREATE INDEX IF NOT EXISTS idx_jobs_prefecture ON jobs(prefecture);
CREATE INDEX IF NOT EXISTS idx_jobs_rank ON jobs(rank);
CREATE INDEX IF NOT EXISTS idx_jobs_score ON jobs(score DESC);
CREATE INDEX IF NOT EXISTS idx_jobs_emp_type ON jobs(emp_type);
CREATE INDEX IF NOT EXISTS idx_jobs_first_seen ON jobs(first_seen_at);

